diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 76020d2b1dbf..1e8bf0910223 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -1533,8 +1533,10 @@ InstCombinerImpl::foldICmpTruncWithTruncOrExt(ICmpInst &Cmp,
       if (!(NoWrapFlags & TruncInst::NoSignedWrap))
         return nullptr;
     } else {
-      // For unsigned and equality comparisons, either both must be nuw or
-      // both must be nsw, we don't care which.
+      // For unsigned comparisons, either both must be nuw or both must be nsw,
+      // we don't care which.
+      // For equality comparisons we can only drop trunc if both are nuw or both
+      // are nsw because without no-wrap the discarded high bits may differ.
       if (!NoWrapFlags)
         return nullptr;
     }

